import { describe, expect, it } from 'vitest';
import {
  clockDistance,
  createDistributedClockMesh,
  createLamportClock,
  lamportLocalEvent,
  lamportSend,
  lamportReceive,
  lamportHappensBefore,
  FIBER_SPEED_FRACTION_C,
} from './clock-distributed';
import type { ProcessClock } from './clock-distributed';

// ─── Fixtures: Edge Network ────────────────────────────────────────

const sanFrancisco: ProcessClock = {
  id: 'pid:sf',
  label: 'SF Edge',
  location: { lat: 37.77, lon: -122.42, region: 'us-west-1' },
  phase: 'active',
  localEpochMs: Date.now(),
  lastHeartbeatMs: Date.now(),
  requestRate: 150,
};

const tokyo: ProcessClock = {
  id: 'pid:tokyo',
  label: 'Tokyo Edge',
  location: { lat: 35.68, lon: 139.69, region: 'ap-northeast-1' },
  phase: 'active',
  localEpochMs: Date.now(),
  lastHeartbeatMs: Date.now(),
  requestRate: 200,
};

const london: ProcessClock = {
  id: 'pid:london',
  label: 'London Edge',
  location: { lat: 51.51, lon: -0.13, region: 'eu-west-1' },
  phase: 'idle',
  localEpochMs: Date.now(),
  lastHeartbeatMs: Date.now() - 5000,
  requestRate: 0,
};

const sydney: ProcessClock = {
  id: 'pid:sydney',
  label: 'Sydney Edge',
  location: { lat: -33.87, lon: 151.21, region: 'ap-southeast-2' },
  phase: 'cold',
  localEpochMs: Date.now(),
  lastHeartbeatMs: null,
  requestRate: 0,
};

// Same data center -- very close
const sfPeer: ProcessClock = {
  id: 'pid:sf-peer',
  label: 'SF Peer',
  location: { lat: 37.77, lon: -122.42, region: 'us-west-1' },
  phase: 'active',
  localEpochMs: Date.now(),
  lastHeartbeatMs: Date.now(),
  requestRate: 100,
};

// ─── Clock Distance ─────────────────────────────────────────────────

describe('clockDistance', () => {
  it('SF to Tokyo has ~45-55ms propagation delay', () => {
    const dist = clockDistance(sanFrancisco, tokyo);
    // Great circle ~8,280 km, fiber path ~11,600 km, at ~200 km/ms = ~58ms
    expect(dist.propagationDelayMs).toBeGreaterThan(30);
    expect(dist.propagationDelayMs).toBeLessThan(80);
  });

  it('SF to SF peer has near-zero propagation', () => {
    const dist = clockDistance(sanFrancisco, sfPeer);
    expect(dist.propagationDelayMs).toBeLessThan(0.1);
    expect(dist.spatialDistanceKm).toBeLessThan(1);
  });

  it('round trip is 2x propagation', () => {
    const dist = clockDistance(sanFrancisco, london);
    expect(dist.roundTripMs).toBeCloseTo(dist.propagationDelayMs * 2, 3);
  });

  it('simultaneity window equals round trip', () => {
    const dist = clockDistance(sanFrancisco, tokyo);
    expect(dist.simultaneityWindowMs).toBe(dist.roundTripMs);
  });

  it('co-located nodes do not require logical clock', () => {
    const dist = clockDistance(sanFrancisco, sfPeer);
    expect(dist.requiresLogicalClock).toBe(false);
  });

  it('distant nodes require logical clock at 1ms tolerance', () => {
    const dist = clockDistance(sanFrancisco, tokyo, 1);
    expect(dist.requiresLogicalClock).toBe(true);
  });

  it('distant nodes do NOT require logical clock at very high tolerance', () => {
    const dist = clockDistance(sanFrancisco, tokyo, 10000);
    expect(dist.requiresLogicalClock).toBe(false);
  });

  it('propagation delay is in picolorenzos', () => {
    const dist = clockDistance(sanFrancisco, tokyo);
    expect(dist.propagationDelayPLo).toBeGreaterThan(0);
    // Should be tiny (ms scale in pLo)
    expect(dist.propagationDelayPLo).toBeLessThan(0.001);
  });

  it('has a gnostic time label', () => {
    const dist = clockDistance(sanFrancisco, tokyo);
    expect(typeof dist.simultaneityGnostic).toBe('string');
  });
});

// ─── Distributed Clock Mesh ─────────────────────────────────────────

describe('createDistributedClockMesh', () => {
  const mesh = createDistributedClockMesh(
    [sanFrancisco, tokyo, london, sydney, sfPeer]
  );

  it('has correct source', () => {
    expect(mesh.source).toBe('GnosisDistributedClockMesh');
  });

  it('has N*(N-1)/2 edges', () => {
    expect(mesh.edges.length).toBe(10); // 5 choose 2
  });

  it('counts active/idle/dark processes', () => {
    expect(mesh.activeCount).toBe(3); // sf, tokyo, sf-peer
    expect(mesh.idleCount).toBe(1); // london
    expect(mesh.darkCount).toBe(1); // sydney (cold)
  });

  it('lit fraction is active / total', () => {
    expect(mesh.litFraction).toBeCloseTo(3 / 5, 5);
  });

  it('network diameter is the maximum propagation delay', () => {
    expect(mesh.networkDiameterMs).toBeGreaterThan(0);
    // Should be one of the longest routes (e.g., London to Sydney or SF to Sydney)
    expect(mesh.networkDiameterMs).toBeGreaterThan(50);
  });

  it('has both PROCESS and VENT edges', () => {
    const types = new Set(mesh.edges.map(e => e.edgeType));
    expect(types.has('PROCESS')).toBe(true); // sf to sf-peer
    expect(types.has('VENT')).toBe(true);    // sf to tokyo
  });

  it('physical ordering fraction is between 0 and 1', () => {
    expect(mesh.physicalOrderingFraction).toBeGreaterThanOrEqual(0);
    expect(mesh.physicalOrderingFraction).toBeLessThanOrEqual(1);
  });

  it('with very high tolerance, all edges are PROCESS', () => {
    const relaxed = createDistributedClockMesh(
      [sanFrancisco, tokyo, london],
      100000 // 100 seconds
    );
    expect(relaxed.physicalOrderingFraction).toBe(1);
    for (const edge of relaxed.edges) {
      expect(edge.edgeType).toBe('PROCESS');
    }
  });
});

// ─── Lamport Clocks ─────────────────────────────────────────────────

describe('Lamport clocks', () => {
  it('starts at counter 0', () => {
    const clock = createLamportClock('proc-a');
    expect(clock.counter).toBe(0);
    expect(clock.processId).toBe('proc-a');
  });

  it('local event increments counter', () => {
    const clock = createLamportClock('proc-a');
    const result = lamportLocalEvent(clock, 'read');
    expect(result.clock.counter).toBe(1);
    expect(result.event.kind).toBe('local');
    expect(result.event.counter).toBe(1);
  });

  it('send increments counter', () => {
    let clock = createLamportClock('proc-a');
    clock = lamportLocalEvent(clock, 'work').clock;
    const result = lamportSend(clock, 'request');
    expect(result.clock.counter).toBe(2);
    expect(result.event.kind).toBe('send');
  });

  it('receive takes max of local and received, then increments', () => {
    let clockA = createLamportClock('proc-a');
    let clockB = createLamportClock('proc-b');

    // A does 5 local events
    for (let i = 0; i < 5; i++) {
      clockA = lamportLocalEvent(clockA, `work-${i}`).clock;
    }
    expect(clockA.counter).toBe(5);

    // B does 1 local event
    clockB = lamportLocalEvent(clockB, 'init').clock;
    expect(clockB.counter).toBe(1);

    // A sends to B (A's counter = 5)
    const sendResult = lamportSend(clockA, 'msg');
    clockA = sendResult.clock; // A is now at 6

    // B receives (B's counter = 1, received = 6)
    const recvResult = lamportReceive(clockB, sendResult.event.counter, 'msg');
    clockB = recvResult.clock;
    // max(1, 6) + 1 = 7
    expect(clockB.counter).toBe(7);
    expect(recvResult.event.kind).toBe('receive');
  });

  it('happensBefore: same process, lower counter → true', () => {
    let clock = createLamportClock('proc-a');
    const e1 = lamportLocalEvent(clock, 'first');
    clock = e1.clock;
    const e2 = lamportLocalEvent(clock, 'second');
    expect(lamportHappensBefore(e1.event, e2.event)).toBe(true);
    expect(lamportHappensBefore(e2.event, e1.event)).toBe(false);
  });

  it('happensBefore: cross-process send/receive → true', () => {
    const clockA = createLamportClock('proc-a');
    const sendResult = lamportSend(clockA, 'ping');
    const clockB = createLamportClock('proc-b');
    const recvResult = lamportReceive(clockB, sendResult.event.counter, 'ping');
    expect(lamportHappensBefore(sendResult.event, recvResult.event)).toBe(true);
  });

  it('happensBefore: concurrent events → null', () => {
    const clockA = createLamportClock('proc-a');
    const clockB = createLamportClock('proc-b');
    const e1 = lamportLocalEvent(clockA, 'work-a');
    const e2 = lamportLocalEvent(clockB, 'work-b');
    // No message chain between them -- concurrent (spacelike)
    expect(lamportHappensBefore(e1.event, e2.event)).toBeNull();
  });
});
